import pandas as pd
import json
import re

# Access the full results from previous query
result_key = 'var_functions.query_db:8'
results = locals()[result_key]

# Extract categories from descriptions
business_categories = []
for business in results:
    desc = business.get('description', '')
    business_id = business.get('business_id', '')

    # Find category list in description
    # Pattern: "services in [categories]" or "services including [categories]"
    categories = []

    if 'services in ' in desc:
        # Extract after "services in "
        start = desc.find('services in ') + 12
        end = desc.find('.', start)
        if end == -1:
            end = len(desc)
        categories_text = desc[start:end].strip()

        # Split by commas and 'and'
        parts = re.split(r',\s*|\sand\s', categories_text)
        for part in parts:
            part = part.strip()
            if part and part not in ['and']:
                categories.append(part)

    elif 'services including ' in desc:
        # Extract after "services including "
        start = desc.find('services including ') + 19
        end = desc.find('.', start)
        if end == -1:
            end = len(desc)
        categories_text = desc[start:end].strip()

        # Split by commas and 'and'
        parts = re.split(r',\s*|\sand\s', categories_text)
        for part in parts:
            part = part.strip()
            if part and part not in ['and']:
                categories.append(part)

    if categories:
        for category in categories:
            business_categories.append({
                'business_id': business_id,
                'category': category
            })

# Convert to DataFrame
business_cat_df = pd.DataFrame(business_categories)

# Show sample
print("__RESULT__:")
print(json.dumps({
    'total_businesses': len(results),
    'businesses_with_categories': len(business_categories),
    'sample': business_categories[:10]
}))

