import pandas as pd
import json
import re

# Get the businesses accepting credit cards
cc_businesses = locals()['var_functions.query_db:16']

# Process all businesses to extract categories
category_data = []
for business in cc_businesses:
    business_id = business['business_id']
    desc = business.get('description', '')

    # Extract categories from description
    categories = []

    if 'services in ' in desc:
        start = desc.find('services in ') + 12
        end = desc.find('.', start)
        if end == -1:
            end = len(desc)
        cat_text = desc[start:end].strip()

        # Split by comma and 'and'
        parts = re.split(r',\s*|\s+and\s+', cat_text)
        for part in parts:
            part = part.strip()
            if part and part not in ['and']:
                # Remove "and" prefix if present
                if part.startswith('and '):
                    part = part[4:]
                categories.append(part)

    elif 'services including ' in desc:
        start = desc.find('services including ') + 19
        end = desc.find('.', start)
        if end == -1:
            end = len(desc)
        cat_text = desc[start:end].strip()

        # Split by comma and 'and'
        parts = re.split(r',\s*|\s+and\s+', cat_text)
        for part in parts:
            part = part.strip()
            if part and part not in ['and']:
                # Remove "and" prefix if present
                if part.startswith('and '):
                    part = part[4:]
                categories.append(part)

    elif 'fields of ' in desc:
        start = desc.find('fields of ') + 10
        end = desc.find('.', start)
        if end == -1:
            end = len(desc)
        cat_text = desc[start:end].strip()

        # Split by comma and 'and'
        parts = re.split(r',\s*|\s+and\s+', cat_text)
        for part in parts:
            part = part.strip()
            if part and part not in ['and']:
                # Remove "and" prefix if present
                if part.startswith('and '):
                    part = part[4:]
                categories.append(part)

    # Add to category data
    for category in categories:
        category_data.append({
            'business_id': business_id,
            'category': category
        })

# Create DataFrame
cat_df = pd.DataFrame(category_data)

# Count businesses per category
category_counts = cat_df['category'].value_counts()

# Get top categories
top_categories = category_counts.head(10)

print("__RESULT__:")
print(json.dumps({
    'total_cc_businesses': len(cc_businesses),
    'total_category_assignments': len(category_data),
    'top_categories': top_categories.to_dict()
}))

